{"cmd":"expect <<'EOF'
set timeout 180
log_user 1
spawn telnet 127.0.0.1 5555

expect {
  -re {Connected to .*} { exp_continue }
  -re {boot: *$} { send "lts console=ttyS0,115200\r" }
  timeout { puts "ERR: no boot prompt"; exit 1 }
}

# Wait for login prompt on serial console
expect {
  -re {login: *$} { send "root\r" }
  -re {~ # *$} {}
  timeout { puts "ERR: no login prompt"; exit 1 }
}

# Ensure we are at shell prompt
expect {
  -re {~ # *$} {}
  timeout { send "\r"; exp_continue }
}

send "echo root:password123 | chpasswd\r"
expect -re {# *$}

send "if ! command -v sshd >/dev/null 2>&1; then apk add --no-cache openssh; fi\r"
expect -re {# *$}

send "if [ -f /etc/ssh/sshd_config ]; then sed -i 's/^#\\?PermitRootLogin .*/PermitRootLogin yes/' /etc/ssh/sshd_config; grep -q '^PermitRootLogin yes' /etc/ssh/sshd_config || echo 'PermitRootLogin yes' >> /etc/ssh/sshd_config; sed -i 's/^#\\?PasswordAuthentication .*/PasswordAuthentication yes/' /etc/ssh/sshd_config; grep -q '^PasswordAuthentication yes' /etc/ssh/sshd_config || echo 'PasswordAuthentication yes' >> /etc/ssh/sshd_config; fi\r"
expect -re {# *$}

send "ssh-keygen -A >/dev/null 2>&1 || true\r"
expect -re {# *$}

send "rc-service sshd restart || rc-service sshd start || /etc/init.d/sshd restart || /etc/init.d/sshd start || /usr/sbin/sshd\r"
expect -re {# *$}

send "echo SETUP_DONE\r"
expect {
  -re {SETUP_DONE} {}
  timeout { puts "ERR: setup marker missing"; exit 1 }
}

send "exit\r"
expect eof
EOF","yield_time_ms":1000,"max_output_tokens":12000}

