send "ssh-keygen -A >/dev/null 2>&1 || true\r"
expect -re {# *$}

send "rc-service sshd restart || rc-service sshd start || /etc/init.d/sshd restart || /etc/init.d/sshd start || /usr/sbin/sshd\r"
expect -re {# *$}

send "echo SETUP_DONE\r"
expect -re {SETUP_DONE}

send "exit\r"
expect eof
